        ];
        
        if (preg_match('/<title>(.*?)<\/title>/is', $html, $matches)) {
            $data['title'] = trim($matches[1]);
        }
        
        if (preg_match('/<meta\s+property=["\']og:title["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['title'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+content=["\']([^"\']+)["\']\s+property=["\']og:title["\']/is', $html, $matches)) {
            $data['title'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+name=["\']twitter:title["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['title'] = trim($matches[1]);
        }
        
        if (preg_match('/<meta\s+property=["\']og:description["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['description'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+content=["\']([^"\']+)["\']\s+property=["\']og:description["\']/is', $html, $matches)) {
            $data['description'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+name=["\']description["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['description'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+name=["\']twitter:description["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['description'] = trim($matches[1]);
        }
        
        if (preg_match('/<meta\s+property=["\']og:image["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['image'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+content=["\']([^"\']+)["\']\s+property=["\']og:image["\']/is', $html, $matches)) {
            $data['image'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+name=["\']twitter:image["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['image'] = trim($matches[1]);
        }
        
        if (preg_match('/<meta\s+property=["\']og:site_name["\']\s+content=["\'](.*?)["\']/is', $html, $matches)) {
            $data['site_name'] = trim($matches[1]);
        } elseif (preg_match('/<meta\s+content=["\']([^"\']+)["\']\s+property=["\']og:site_name["\']/is', $html, $matches)) {
            $data['site_name'] = trim($matches[1]);
        }
        
        return $data;
    }
    
    public function show(Request $request)
    {
        return view('website-preview', [
            'url' => $request->input('url', '')
        ]);
    }
